{
  "grammar": [
    {
      "pattern": "可以 + [action] + [object] + 嗎？",
      "structure": ["可以", "action", "object", "嗎"],
      "explanation_en": "Use '可以...嗎？' to politely ask for permission or request an action. It is a standard polite form in service settings.",
      "title": "Polite Request with 可以...嗎？",
      "meaning": "May I...? / Can I...?",
      "when_to_use": ["When asking for permission to do something", "When requesting an action from a service person"],
      "when_not_to_use": ["When making a direct command", "When speaking to close friends in casual settings"],
      "pragmatic_notes": "In Taiwan, using '可以...嗎？' is very common and considered polite. It softens the request and shows respect.",
      "word_order_notes": "Place '可以' at the beginning, followed by the verb, then the object, and end with '嗎'.",
      "english_contrast": "English uses 'Can I...?' or 'May I...?' at the beginning, similar to Chinese structure.",
      "korean_contrast": "Korean uses '~을/를 해도 될까요?' which is a permission-seeking form, similar in politeness.",
      "negative_examples": [
        {
          "text": "可以嗎？",
          "error": "Missing action and object; incomplete request."
        }
      ],
      "incorrect_examples": [
        {
          "text": "可以嗎？",
          "error": "Missing action and object; incomplete request."
        }
      ],
      "transformation_drills": ["Change '可以看書嗎？' to '可以看電影嗎？'", "Change '可以喝咖啡嗎？' to '可以喝茶嗎？'"],
      "production_drills": ["Ask to use the restroom: '可以...廁所嗎？'", "Ask to sit here: '可以...這裡嗎？'"],
      "common_error_patterns": ["Forgetting '嗎' at the end", "Using '可以' after the verb"],
      "repair_feedback": {
        "word_order": "Remember: 可以 + verb + object + 嗎",
        "politeness": "This structure is polite; avoid using direct commands.",
        "vocabulary": "Use appropriate verbs like 看, 喝, 坐, 用."
      }
    },
    {
      "pattern": "想要 + [object]",
      "structure": ["想要", "object"],
      "explanation_en": "Use '想要' to express what you want politely. It is softer than '要' and commonly used in ordering.",
      "title": "Expressing Wants with 想要",
      "meaning": "I would like...",
      "when_to_use": ["When ordering food or drinks", "When expressing a desire politely"],
      "when_not_to_use": ["When making a strong demand", "When asking for permission"],
      "pragmatic_notes": "In Taiwan, '想要' is very common in cafés and shops. It sounds polite and natural.",
      "word_order_notes": "Place '想要' before the object. No additional verb needed.",
      "english_contrast": "English uses 'I would like...' which is similar in politeness.",
      "korean_contrast": "Korean uses '~을/를 원합니다' which is a direct expression of want, but '想要' is softer.",
      "negative_examples": [
        {
          "text": "想要嗎？",
          "error": "Missing object; incomplete request."
        }
      ],
      "incorrect_examples": [
        {
          "text": "想要嗎？",
          "error": "Missing object; incomplete request."
        }
      ],
      "transformation_drills": ["Change '想要咖啡' to '想要茶'", "Change '想要水' to '想要牛奶'"],
      "production_drills": ["Order a drink: '我想要...'", "Order food: '我想要...'"],
      "common_error_patterns": ["Using '想要' with a verb unnecessarily", "Forgetting the object"],
      "repair_feedback": {
        "word_order": "Remember: 想要 + object",
        "politeness": "This is polite; avoid using just '要' in formal settings.",
        "vocabulary": "Use object nouns like 咖啡, 茶, 水."
      }
    },
    {
      "pattern": "不好意思，[request]",
      "structure": ["不好意思", "request"],
      "explanation_en": "Use '不好意思' as a polite softener before making a request. It shows politeness and hesitation.",
      "title": "Polite Softener with 不好意思",
      "meaning": "Excuse me, ... / Sorry to bother, ...",
      "when_to_use": ["When starting a request in a shop or café", "When you need to get someone's attention"],
      "when_not_to_use": ["When you are apologizing for a mistake", "In very casual settings with friends"],
      "pragmatic_notes": "In Taiwan, '不好意思' is used frequently to soften requests. It is more polite than just stating the request.",
      "word_order_notes": "Place '不好意思' at the beginning of the sentence, followed by the request.",
      "english_contrast": "English uses 'Excuse me' or 'Sorry to bother you' at the beginning.",
      "korean_contrast": "Korean uses '실례합니다' or '죄송합니다' similarly to soften requests.",
      "negative_examples": [
        {
          "text": "不好意思，可以嗎？",
          "error": "Missing action and object; incomplete request."
        }
      ],
      "incorrect_examples": [
        {
          "text": "不好意思，可以嗎？",
          "error": "Missing action and object; incomplete request."
        }
      ],
      "transformation_drills": ["Change '不好意思，我想要咖啡' to '不好意思，我想要茶'", "Change '不好意思，可以看菜單嗎？' to '不好意思，可以看書嗎？'"],
      "production_drills": ["Ask for a menu: '不好意思，可以看...嗎？'", "Ask for help: '不好意思，幫我...'"],
      "common_error_patterns": ["Using '不好意思' at the end of the sentence", "Forgetting to complete the request"],
      "repair_feedback": {
        "word_order": "Remember: 不好意思 + request",
        "politeness": "This softener makes your request polite.",
        "vocabulary": "Use appropriate request structures after 不好意思."
      }
    }
  ]
}
